int strcmp1(char *s,char *t)
{
	for(;*s++==*t++;)
	if(*s=='\0')
        return 0;
	return(*s-*t);
}

选项.B:
int strcmp2(char *s,char *t)
{
	for(;*s++==*t++;)
	if(!*s)
	return 0;
	return(*s-*t);
}

选项.C:
int strcmp3(char *s,char *t)
{
	for(;*s==*t;)
	{
		if(!*t)
		return 0;
		t++;
		s++;	
		return(*s-*t);
	}
}

选项.D:
int strcmp4(char *s,char *t)
{
	for(;*s==*t;s++,t++)
		if(!*s)
		return 0;
		return(*t-*s);
}

